// Transform HubSpot contacts into batch-memorize payload
const items = $input.all();

// Each item.json contains HubSpot contact properties
const rows = items.map(item => ({
  email: item.json.email || item.json.properties?.email || '',
  firstname: item.json.firstname || item.json.properties?.firstname || '',
  lastname: item.json.lastname || item.json.properties?.lastname || '',
  phone: item.json.phone || item.json.properties?.phone || '',
  company: item.json.company || item.json.properties?.company || '',
  jobtitle: item.json.jobtitle || item.json.properties?.jobtitle || '',
  mobilephone: item.json.mobilephone || item.json.properties?.mobilephone || '',
}));

// Filter out rows without email
const validRows = rows.filter(r => r.email);

// TODO: Replace collection IDs with your actual IDs from client.collections.list()
const payload = {
  source: 'Hubspot',
  mapping: {
    entityType: 'contact',
    email: 'email',
    runName: 'n8n-hubspot-sync-' + Date.now(),
    properties: {
      // Structured fields — stored directly, no AI
      email:        { sourceField: 'email',       collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      first_name:   { sourceField: 'firstname',   collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      last_name:    { sourceField: 'lastname',     collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      phone:        { sourceField: 'phone',        collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      mobile_phone: { sourceField: 'mobilephone',  collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      company:      { sourceField: 'company',      collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
      job_title:    { sourceField: 'jobtitle',     collectionId: 'YOUR_STANDARD_COL_ID', collectionName: 'Contacts Standard Schema' },
    },
  },
  rows: validRows,
  chunkSize: 1,
};

return [{ json: payload }];
